public static int knapsack(int capacity, int [][] items) {
    int weight = 0, value = 0;
    int n = items.length;
    int memo[][] = new int[n + 1][capacity + 1];
    for (int i = 0; i <= n ; i++)
    {
        if (i - 1 >= 0) {
            weight = items[i - 1][0];
            value = items[i - 1][1];
        }
        for (int j = 0; j <= capacity; j++)
        {
            if (i == 0 || j == 0) {
                memo[i][j] = 0;
            }
            else if (weight < j) {
                            memo[i][j] = Math.max(memo[i - 1][j], value + memo[i - 1][j - weight]);
            }
            else {
                memo[i][j] = memo [i-1][j];
            }
        }
    }
    return memo[n][capacity];
}

